import React, { useRef, useMemo, useState, useEffect } from "react";
import { Canvas, useFrame } from "@react-three/fiber";
import * as THREE from "three";
import "../style/NeuralParticles.css";

/* ══════════════════════════════════════════════════════
   Particle Neural Network
   ─ Nodes: glowing sphere meshes (no orbit particles)
   ─ Edges: 10 stream particles each, lerped on CPU
   ─ Transparent canvas — blends with page background
══════════════════════════════════════════════════════ */

const NODES = [
  // Input — x = -3.6  (4 nodes)
  { id: 0,  pos: [-3.6,  1.8,  0.1], layer: 0 },
  { id: 1,  pos: [-3.6,  0.5, -0.2], layer: 0 },
  { id: 2,  pos: [-3.6, -0.7,  0.2], layer: 0 },
  { id: 3,  pos: [-3.6, -2.0, -0.1], layer: 0 },
  // Hidden 1 — x = -1.8  (6 nodes)
  { id: 4,  pos: [-1.8,  2.5,  0.3], layer: 1 },
  { id: 5,  pos: [-1.8,  1.3, -0.3], layer: 1 },
  { id: 6,  pos: [-1.8,  0.2,  0.4], layer: 1 },
  { id: 7,  pos: [-1.8, -0.9, -0.2], layer: 1 },
  { id: 8,  pos: [-1.8, -2.0,  0.1], layer: 1 },
  { id: 9,  pos: [-1.8, -3.0, -0.3], layer: 1 },
  // Hidden 2 — x = 0.2  (6 nodes)
  { id: 10, pos: [ 0.2,  2.5, -0.2], layer: 2 },
  { id: 11, pos: [ 0.2,  1.3,  0.3], layer: 2 },
  { id: 12, pos: [ 0.2,  0.2, -0.3], layer: 2 },
  { id: 13, pos: [ 0.2, -0.9,  0.4], layer: 2 },
  { id: 14, pos: [ 0.2, -2.0, -0.1], layer: 2 },
  { id: 15, pos: [ 0.2, -3.0,  0.2], layer: 2 },
  // Hidden 3 — x = 2.0  (5 nodes)
  { id: 16, pos: [ 2.0,  2.0,  0.2], layer: 3 },
  { id: 17, pos: [ 2.0,  0.9, -0.3], layer: 3 },
  { id: 18, pos: [ 2.0, -0.2,  0.3], layer: 3 },
  { id: 19, pos: [ 2.0, -1.3, -0.2], layer: 3 },
  { id: 20, pos: [ 2.0, -2.5,  0.1], layer: 3 },
  // Output — x = 3.6  (3 nodes)
  { id: 21, pos: [ 3.6,  1.2,  0.1], layer: 4 },
  { id: 22, pos: [ 3.6,  0.0, -0.2], layer: 4 },
  { id: 23, pos: [ 3.6, -1.2,  0.2], layer: 4 },
];

const LAYER_COLORS = ["#60a5fa", "#22d3ee", "#a78bfa", "#34d399", "#fb923c"];

// Fully-connected between consecutive layers
const EDGES = [];
for (let i = 0; i < NODES.length; i++) {
  for (let j = i + 1; j < NODES.length; j++) {
    if (NODES[j].layer === NODES[i].layer + 1) EDGES.push([i, j]);
  }
}

const STREAM = 10;  // particles per edge (CPU lerp)

/* ── Stream shaders ── */
const streamVert = /* glsl */ `
  attribute float aProgress;
  varying  float vProgress;
  void main() {
    vProgress = aProgress;
    float fade = sin(aProgress * 3.14159);
    vec4 mv    = modelViewMatrix * vec4(position, 1.0);
    gl_Position  = projectionMatrix * mv;
    gl_PointSize = 36.0 * (0.3 + fade * 0.7) / -mv.z;
  }`;

const streamFrag = /* glsl */ `
  varying float vProgress;
  void main() {
    float d = length(gl_PointCoord - vec2(0.5));
    if (d > 0.5) discard;
    float glow = pow(1.0 - d * 2.0, 2.2);
    float fade = sin(vProgress * 3.14159);
    vec3  col  = mix(vec3(0.0, 0.88, 1.0), vec3(0.72, 0.22, 1.0), vProgress);
    gl_FragColor = vec4(col, glow * fade * 0.9);
  }`;

/* ── Thin static lines showing topology ── */
function NetworkLines() {
  const obj = useMemo(() => {
    const pts = new Float32Array(EDGES.length * 6);
    EDGES.forEach(([a, b], i) => {
      pts.set(NODES[a].pos, i * 6);
      pts.set(NODES[b].pos, i * 6 + 3);
    });
    const geo = new THREE.BufferGeometry();
    geo.setAttribute("position", new THREE.BufferAttribute(pts, 3));
    const mat = new THREE.LineBasicMaterial({
      color: "#3b6be0",
      transparent: true,
      opacity: 0.13,
      blending: THREE.AdditiveBlending,
    });
    return new THREE.LineSegments(geo, mat);
  }, []);
  return <primitive object={obj} />;
}

/* ── Single glowing node sphere ── */
function NodeMesh({ position, layer }) {
  const groupRef = useRef();
  const phase = useMemo(() => Math.random() * Math.PI * 2, []);
  const color = LAYER_COLORS[layer];
  const r = 0.13;

  useFrame(({ clock }) => {
    if (!groupRef.current) return;
    const s = 1 + Math.sin(clock.elapsedTime * 1.6 + phase) * 0.09;
    groupRef.current.scale.setScalar(s);
  });

  return (
    <group ref={groupRef} position={position}>
      {/* Solid core */}
      <mesh>
        <sphereGeometry args={[r, 14, 14]} />
        <meshBasicMaterial color={color} />
      </mesh>
      {/* Inner glow halo */}
      <mesh>
        <sphereGeometry args={[r * 2.4, 10, 10]} />
        <meshBasicMaterial color={color} transparent opacity={0.20}
          blending={THREE.AdditiveBlending} depthWrite={false} />
      </mesh>
      {/* Outer soft bloom */}
      <mesh>
        <sphereGeometry args={[r * 5.0, 10, 10]} />
        <meshBasicMaterial color={color} transparent opacity={0.055}
          blending={THREE.AdditiveBlending} depthWrite={false} />
      </mesh>
    </group>
  );
}

/* ── Edge stream particles (CPU lerp) ── */
function StreamParticles() {
  const { streamGeo, sd } = useMemo(() => {
    const n       = EDGES.length * STREAM;
    const posA    = new Float32Array(n * 3);
    const posB    = new Float32Array(n * 3);
    const tArr    = new Float32Array(n);
    const spd     = new Float32Array(n);
    const livePos = new Float32Array(n * 3);
    const liveT   = new Float32Array(n);
    EDGES.forEach(([ai, bi], ei) => {
      const a = NODES[ai].pos, b = NODES[bi].pos;
      for (let p = 0; p < STREAM; p++) {
        const i = ei * STREAM + p;
        posA.set(a, i * 3); posB.set(b, i * 3);
        tArr[i] = p / STREAM;
        spd[i]  = 0.003 + Math.random() * 0.005;
        const t = tArr[i];
        livePos[i*3]   = a[0] + (b[0]-a[0])*t;
        livePos[i*3+1] = a[1] + (b[1]-a[1])*t;
        livePos[i*3+2] = a[2] + (b[2]-a[2])*t;
        liveT[i] = t;
      }
    });
    const g = new THREE.BufferGeometry();
    g.setAttribute("position",
      new THREE.BufferAttribute(livePos, 3).setUsage(THREE.DynamicDrawUsage));
    g.setAttribute("aProgress",
      new THREE.BufferAttribute(liveT,   1).setUsage(THREE.DynamicDrawUsage));
    return { streamGeo: g, sd: { posA, posB, tArr, spd, livePos, liveT } };
  }, []);

  useFrame(() => {
    const { posA, posB, tArr, spd, livePos, liveT } = sd;
    const n = EDGES.length * STREAM;
    for (let i = 0; i < n; i++) {
      tArr[i] += spd[i];
      if (tArr[i] > 1) tArr[i] -= 1;
      const t = tArr[i];
      livePos[i*3]   = posA[i*3]   + (posB[i*3]   - posA[i*3])   * t;
      livePos[i*3+1] = posA[i*3+1] + (posB[i*3+1] - posA[i*3+1]) * t;
      livePos[i*3+2] = posA[i*3+2] + (posB[i*3+2] - posA[i*3+2]) * t;
      liveT[i] = t;
    }
    streamGeo.attributes.position.needsUpdate = true;
    streamGeo.attributes.aProgress.needsUpdate = true;
  });

  return (
    <points geometry={streamGeo}>
      <shaderMaterial
        vertexShader={streamVert}
        fragmentShader={streamFrag}
        transparent depthWrite={false} blending={THREE.AdditiveBlending}
      />
    </points>
  );
}

/* ── Full network scene ── */
function ParticleNet() {
  const groupRef = useRef();

  useFrame(({ clock }) => {
    if (groupRef.current) {
      const t = clock.elapsedTime;
      groupRef.current.rotation.y = Math.sin(t * 0.12) * 0.28;
      groupRef.current.rotation.x = Math.sin(t * 0.08) * 0.06;
    }
  });

  return (
    <group ref={groupRef}>
      <NetworkLines />
      {NODES.map((nd) => (
        <NodeMesh key={nd.id} position={nd.pos} layer={nd.layer} />
      ))}
      <StreamParticles />
    </group>
  );
}

/* ── Lazy-mount wrapper ── */
function LazyCanvas({ children, ...props }) {
  const wrapRef = useRef();
  const [visible, setVisible] = useState(false);
  useEffect(() => {
    const obs = new IntersectionObserver(
      ([e]) => { if (e.isIntersecting) setVisible(true); },
      { threshold: 0.1 }
    );
    if (wrapRef.current) obs.observe(wrapRef.current);
    return () => obs.disconnect();
  }, []);
  return (
    <div ref={wrapRef} style={{ width: "100%", height: "100%" }}>
      {visible && <Canvas {...props}>{children}</Canvas>}
    </div>
  );
}

const NeuralParticles = () => (
  <div className="neural-particles-wrap">
    <div className="neural-particles-canvas" aria-hidden="true">
      <LazyCanvas
        camera={{ position: [0, 0, 9], fov: 55 }}
        gl={{ antialias: true, alpha: true }}
      >
        <ParticleNet />
      </LazyCanvas>
    </div>
    <div className="neural-particles-legend">
      {["Input", "Hidden 1", "Hidden 2", "Hidden 3", "Output"].map((label, i) => (
        <span key={label} className="np-legend-item">
          <span className="np-dot" style={{ background: LAYER_COLORS[i] }} />
          {label}
        </span>
      ))}
      <span className="np-legend-item np-stream">
        <span className="np-stream-line" />Signal stream
      </span>
    </div>
  </div>
);

export default NeuralParticles;
